+fn append_perf_sample(
+    buckets: &mut BTreeMap<String, PerfSampleBucket>,
+    benchmark: String,
+    nodes: Option<usize>,
+    edges: Option<usize>,
+    ns: u64,
+) {
+    let bucket = buckets
+        .entry(benchmark)
+        .or_insert_with(|| PerfSampleBucket {
+            nodes,
+            edges,
+            samples_ns: Vec::new(),
+        });
+    bucket.nodes = bucket.nodes.or(nodes);
+    bucket.edges = bucket.edges.or(edges);
+    bucket.samples_ns.push(ns);
+}
